import{_ as t,o as a,c as i,a2 as l}from"./chunks/framework.ufzXw1qY.js";const h=JSON.parse('{"title":"Ultimate Plugin Development Doctrine","description":"Rules for building plugins that are clear, safe, observable, and fleet-compatible.","frontmatter":{"title":"Ultimate Plugin Development Doctrine","description":"Rules for building plugins that are clear, safe, observable, and fleet-compatible."},"headers":[],"relativePath":"best-practices/plugin-development.md","filePath":"best-practices/plugin-development.md"}'),n={name:"best-practices/plugin-development.md"};function r(o,e,s,u,d,p){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="ultimate-plugin-development-doctrine" tabindex="-1">Ultimate Plugin Development Doctrine <a class="header-anchor" href="#ultimate-plugin-development-doctrine" aria-label="Permalink to &quot;Ultimate Plugin Development Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> A plugin is not allowed to be clever in private. It must be explicit in capability, predictable in side effects, and documented in behavior.</p></blockquote><hr><h2 id="_1-plugin-purpose" tabindex="-1">1. Plugin Purpose <a class="header-anchor" href="#_1-plugin-purpose" aria-label="Permalink to &quot;1. Plugin Purpose&quot;">​</a></h2><p>A plugin should exist only when it creates a reusable capability boundary. Do not create plugins for trivial wrapper vanity.</p><hr><h2 id="_2-plugin-contracts" tabindex="-1">2. Plugin Contracts <a class="header-anchor" href="#_2-plugin-contracts" aria-label="Permalink to &quot;2. Plugin Contracts&quot;">​</a></h2><p>Every plugin must define clearly:</p><ul><li>what it exposes</li><li>what it depends on</li><li>what permissions it needs</li><li>what inputs are accepted</li><li>what outputs are guaranteed</li></ul><hr><h2 id="_3-safety-rules" tabindex="-1">3. Safety Rules <a class="header-anchor" href="#_3-safety-rules" aria-label="Permalink to &quot;3. Safety Rules&quot;">​</a></h2><p>Plugins must:</p><ul><li>avoid hidden credential usage</li><li>avoid destructive defaults</li><li>surface useful errors</li><li>respect operator confirmation gates</li></ul><hr><h2 id="_4-maintainability-rules" tabindex="-1">4. Maintainability Rules <a class="header-anchor" href="#_4-maintainability-rules" aria-label="Permalink to &quot;4. Maintainability Rules&quot;">​</a></h2><p>A plugin that nobody can debug is a trap. Document lifecycle, failure modes, expected env, and integration points.</p><hr><h2 id="_5-final-rule" tabindex="-1">5. Final Rule <a class="header-anchor" href="#_5-final-rule" aria-label="Permalink to &quot;5. Final Rule&quot;">​</a></h2><p><strong>Plugins should compress complexity for the rest of the fleet, not relocate it into a dark corner.</strong></p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code></td></tr><tr><td><strong>Plugin-Namespace</strong></td><td>0.0</td><td><code>opencode-plugin-*</code> Prefix</td></tr></tbody></table>',24)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
